import sqlite3
from typing import Optional, Dict, Any


def get_order(db_path: str, authenticated_user_id: int, order_id: int) -> Optional[Dict[str, Any]]:
    """
    Retrieve order information from a SQLite database with server-side authorization.

    The query scopes the order lookup by both order_id AND the authenticated user_id,
    ensuring that a user can only access their own orders. The authenticated_user_id
    should come from the server-side session/token, NOT from client input.

    Args:
        db_path: Path to the SQLite database file.
        authenticated_user_id: The user ID from the authenticated session (server-side).
        order_id: The ID of the order to retrieve.

    Returns:
        A dictionary containing the order data, or None if not found or not authorized.
    """
    conn = None
    try:
        conn = sqlite3.connect(db_path)
        conn.row_factory = sqlite3.Row

        cursor = conn.cursor()

        # SECURE: Load the resource by both its identifier AND the authenticated user scope.
        # This ensures the user can only access orders that belong to them.
        # Uses parameterized query to prevent SQL injection.
        cursor.execute(
            "SELECT * FROM orders WHERE id = ? AND user_id = ?",
            (order_id, authenticated_user_id)
        )

        row = cursor.fetchone()

        if row is None:
            return None

        # Convert the Row object to a plain dictionary.
        # SECURE: Only return allowlisted fields instead of blindly returning everything.
        order_dict = dict(row)

        # Allowlist of fields safe to return to the user.
        # This prevents leaking internal/privileged fields.
        allowed_fields = {
            "id",
            "user_id",
            "order_date",
            "status",
            "total_amount",
            "shipping_address",
            "items",
            "created_at",
            "updated_at",
        }

        filtered_order = {
            key: value for key, value in order_dict.items()
            if key in allowed_fields
        }

        return filtered_order

    except sqlite3.Error as e:
        print(f"Database error: {e}")
        return None
    finally:
        if conn:
            conn.close()


def update_order(db_path: str, authenticated_user_id: int, order_id: int,
                 updates: Dict[str, Any]) -> bool:
    """
    Update order information with server-side authorization and field allowlisting.

    Args:
        db_path: Path to the SQLite database file.
        authenticated_user_id: The user ID from the authenticated session (server-side).
        order_id: The ID of the order to update.
        updates: Dictionary of fields to update.

    Returns:
        True if the update was successful, False otherwise.
    """
    # SECURE: Allowlist which fields can be updated by the user.
    # Privileged fields like 'user_id', 'internal_notes', 'discount_override'
    # are NOT in this list and cannot be mass-assigned.
    updatable_fields = {
        "shipping_address",
        "status",
    }

    # Filter out any fields that are not in the allowlist
    safe_updates = {
        key: value for key, value in updates.items()
        if key in updatable_fields
    }

    if not safe_updates:
        return False

    conn = None
    try:
        conn = sqlite3.connect(db_path)
        cursor = conn.cursor()

        # SECURE: First verify the order belongs to the authenticated user
        cursor.execute(
            "SELECT id FROM orders WHERE id = ? AND user_id = ?",
            (order_id, authenticated_user_id)
        )

        if cursor.fetchone() is None:
            return False

        # Build parameterized UPDATE query with only safe fields
        set_clause = ", ".join(f"{field} = ?" for field in safe_updates.keys())
        values = list(safe_updates.values())

        # SECURE: Scope the UPDATE by both order_id and user_id
        query = f"UPDATE orders SET {set_clause} WHERE id = ? AND user_id = ?"
        values.extend([order_id, authenticated_user_id])

        cursor.execute(query, values)
        conn.commit()

        return cursor.rowcount > 0

    except sqlite3.Error as e:
        print(f"Database error: {e}")
        return False
    finally:
        if conn:
            conn.close()